import React, { useState } from "react";

export default function MessageForm({ onSend }) {
  const [text, setText] = useState("");
  const [files, setFiles] = useState([]);
  const [sending, setSending] = useState(false);
  const quickEmojis = ["😀", "😂", "😍", "🔥", "👍", "🎉"];

  const addEmoji = (emoji) => setText((prev) => `${prev}${emoji}`);

  const submit = (event) => {
    event.preventDefault();
    if (!text.trim() && !files.length) return;
    setSending(true);
    Promise.resolve(onSend({ content: text, files }))
      .then(() => {
        setText("");
        setFiles([]);
      })
      .finally(() => setSending(false));
  };

  return (
    <form className="message-form" onSubmit={submit}>
      <div className="message-input-wrap">
        <input type="text" placeholder="Type your message here..." value={text} onChange={(event) => setText(event.target.value)} maxLength={1000} />
        <div className="emoji-quick-row">
          {quickEmojis.map((emoji) => (
            <button key={emoji} type="button" className="emoji-btn" onClick={() => addEmoji(emoji)}>{emoji}</button>
          ))}
          <label className="file-picker-btn">
            Attach
            <input
              type="file"
              multiple
              onChange={(event) => setFiles(Array.from(event.target.files || []).slice(0, 5))}
            />
          </label>
        </div>
        {files.length ? <small className="attach-hint">{files.map((file) => file.name).join(", ")}</small> : null}
      </div>
      <button className="primary-btn" type="submit" disabled={sending}>{sending ? "Sending..." : "Send"}</button>
    </form>
  );
}
